/** Resolve a help query. Returns help text. */
export function resolveHelp(topic?: string): string {
  if (!topic) return helpDirectory;
  const dot = topic.indexOf('.');
  if (dot === -1) {
    if (helpTools[topic]) return helpTools[topic];
    const ep = helpEndpoints[topic];
    if (ep) return ep.summary;
    const all = [...Object.keys(helpTools), ...Object.keys(helpEndpoints)];
    return 'Unknown topic: ' + topic + '. Available: ' + all.join(', ');
  }
  const epName = topic.slice(0, dot);
  const methodName = topic.slice(dot + 1);
  const ep = helpEndpoints[epName];
  if (!ep) return 'Unknown endpoint: ' + epName;
  const method = ep.methods[methodName];
  if (method) return method;
  return 'Unknown method: ' + methodName + ' on ' + epName + '. Available: ' + Object.keys(ep.methods).join(', ');
}
